import { useState, useEffect, useRef } from "react";

const MAGENTA = "#C7238E";
const ORANGE = "#F5A623";
const DARK = "#1A1A1A";
const DARKER = "#111111";
const LIGHT_PINK = "#FDF0F7";

const navItems = ["Home", "About", "Experience", "Team", "Partners", "Events", "Contact"];

function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVisible(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function Section({ id, children, className = "", dark = true }) {
  const [ref, visible] = useInView();
  return (
    <section
      ref={ref}
      id={id}
      className={className}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(40px)",
        transition: "opacity 0.8s ease, transform 0.8s ease",
        padding: "80px 20px",
        background: dark ? DARK : "#0D0D0D",
        minHeight: "60vh",
      }}
    >
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>{children}</div>
    </section>
  );
}

function SectionTitle({ text, accent }) {
  return (
    <div style={{ marginBottom: 40 }}>
      <h2 style={{ fontSize: "clamp(28px, 5vw, 42px)", fontWeight: 900, color: "#fff", margin: 0, letterSpacing: "-1px" }}>{text}</h2>
      <div style={{ width: 60, height: 4, background: accent || MAGENTA, marginTop: 12, borderRadius: 2 }} />
    </div>
  );
}

function Card({ children, style = {} }) {
  return (
    <div style={{
      background: "rgba(255,255,255,0.04)",
      border: "1px solid rgba(255,255,255,0.08)",
      borderRadius: 12,
      padding: "24px",
      backdropFilter: "blur(10px)",
      ...style,
    }}>
      {children}
    </div>
  );
}

function StatCard({ number, label }) {
  return (
    <div style={{ textAlign: "center", flex: "1 1 140px" }}>
      <div style={{ fontSize: "clamp(32px, 6vw, 52px)", fontWeight: 900, color: MAGENTA, lineHeight: 1 }}>{number}</div>
      <div style={{ fontSize: 13, color: "#999", marginTop: 6, textTransform: "uppercase", letterSpacing: 1 }}>{label}</div>
    </div>
  );
}

function TeamMember({ name, role, secondary, accent = MAGENTA }) {
  return (
    <div style={{
      background: "rgba(255,255,255,0.03)",
      border: `1px solid ${accent}22`,
      borderRadius: 10,
      padding: "18px 20px",
      borderLeft: `3px solid ${accent}`,
    }}>
      <div style={{ fontWeight: 700, color: "#fff", fontSize: 16 }}>{name}</div>
      <div style={{ color: accent, fontSize: 13, fontWeight: 600, marginTop: 3 }}>{role}</div>
      {secondary && <div style={{ color: "#888", fontSize: 12, marginTop: 5 }}>{secondary}</div>}
    </div>
  );
}

